// Citas existentes
const appointments = $('GetTurnos').all().map(i => i.json);

// Fecha actual
const ahora = new Date();

// Filtrar citas futuras y reservadas
const citasFuturas = appointments.filter(cita => {
  return (
    cita.estado === 'reservado' &&
    new Date(cita.fecha_hora_inicio) > ahora
  );
});

// Si no tiene citas futuras
if (citasFuturas.length === 0) {
  return [{
    json: {
      tiene_citas: false,
      mensaje: '❌ No tenés citas futuras registradas para reagendar.'
    }
  }];
}

// Si tiene una sola cita
if (citasFuturas.length === 1) {
  const cita = citasFuturas[0];
  const inicio = new Date(cita.fecha_hora_inicio);

  const mensaje =
`📅 Tenés una cita programada:

📆 Fecha: ${inicio.toLocaleDateString('es-ES')}
⏰ Hora: ${inicio.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}

¿Deseás *reagendar* esta cita?
Respondé *SI* para continuar o *NO* para mantenerla.`;

  return [{
    json: {
      unica_cita: true,
      cita,
      mensaje,
      CallerID: $('When Executed by Another Workflow').first().json.CallerID,
      Instance: $('When Executed by Another Workflow').first().json.Instance
    }
  }];
}

// Si tiene más de una cita
let menu = `📅 Tenés las siguientes citas programadas:\n\n`;

citasFuturas.forEach((cita, index) => {
  const inicio = new Date(cita.fecha_hora_inicio);
  menu += `${index + 1}️⃣ ${inicio.toLocaleDateString('es-ES')} - ${inicio.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}\n`;
});

menu += `\nPor favor, respondé con el *número* de la cita que deseás *reagendar*.`;

return [{
  json: {
    unica_cita: false,
    citas: citasFuturas,
    mensaje: menu,
    CallerID: $('When Executed by Another Workflow').first().json.CallerID,
    Instance: $('When Executed by Another Workflow').first().json.Instance
  }
}];

// JSON en formato string (array de citas)
const jsonString = $input.first().json.citas;

// Opción ingresada por el usuario
const opcionRaw = $('When Executed by Another Workflow').first().json.Message;
const opcion = parseInt(opcionRaw, 10);

// Parsear JSON string a JSON real
const citas = JSON.parse(jsonString);

// Validar que sea número
if (isNaN(opcion)) {
  return [{
    json: {
      valido: false,
      mensaje: '❌ Opción inválida. Por favor, respondé con un número.'
    }
  }];
}

// Validar rango
if (opcion < 1 || opcion > citas.length) {
  return [{
    json: {
      valido: false,
      mensaje: '❌ El número ingresado no corresponde a ninguna cita.'
    }
  }];
}

// Obtener la cita seleccionada (1 → índice 0)
const citaSeleccionada = citas[opcion - 1];

// Fecha de inicio de la cita
const inicio = new Date(citaSeleccionada.fecha_hora_inicio);

// Mensaje de reagendamiento
const mensaje =
`📆 Fecha actual: ${inicio.toLocaleDateString('es-ES')}
⏰ Hora actual: ${inicio.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })}

¿Para qué día querés agendar la consulta?

📅 Escribí la fecha en formato DD/MM/AAAA.`;

// OK
return [{
  json: {
    valido: true,
    eleccion_usuario: opcion,
    cita_seleccionada: citaSeleccionada,
    mensaje
  }
}];

// Input del usuario (ej: "1", "2", etc.)
const choiceRaw = $('When Executed by Another Workflow').first().json.Message;
const index = parseInt(choiceRaw, 10);

// Validar input numérico
if (isNaN(index) || index < 1) {
  return [{
    json: {
      valido: false,
      mensaje: '❌ Opción inválida. Respondé con el número del horario.'
    }
  }];
}

// Horarios disponibles (array de "HH:mm")
const horariosDisponibles = $('get_HorariosDisponibles').first().json.HorariosDisponibles;

// Validar que esté dentro del array
if (index > horariosDisponibles.length) {
  return [{
    json: {
      valido: false,
      mensaje: '❌ El horario seleccionado no existe.'
    }
  }];
}

// Hora elegida (HH:mm)
const horaElegida = horariosDisponibles[index - 1];

// Fecha base ISO
const fechaBaseISO = $('Get_date').first().json.fecha_selected;
const inicioElegido = new Date(fechaBaseISO);

// Setear hora elegida
const [hh, mm] = horaElegida.split(':').map(Number);
inicioElegido.setUTCHours(hh, mm, 0, 0);

// Duración
const duracion = $('GetDoctor1').first().json.duracion_consulta;
const finElegido = new Date(inicioElegido);
finElegido.setMinutes(finElegido.getMinutes() + duracion);

// Mensaje de confirmación
const mensaje =
`📅 *Confirmación de turno*

👨‍⚕️ Doctor: ${$('GetDoctor1').first().json.nombre}
👤 Paciente: ${$('Get_appointment1').first().json.paciente_nombre}
📆 Fecha: ${inicioElegido.toLocaleDateString('es-ES')}
⏰ Hora: ${horaElegida}
⌛ Duración: ${duracion} minutos

¿Los datos son correctos?
Respondé *SI* para confirmar o *NO* para cancelar.`;

// OK
return [{
  json: {
    valido: true,
    fecha_hora_inicio: inicioElegido.toISOString(),
    fecha_hora_fin: finElegido.toISOString(),
    mensaje
  }
}];

const texto = $('When Executed by Another Workflow').first().json.Message;

// 1. Validar formato dd/MM/yyyy con regex estricta
const regex = /^(0[1-9]|[12][0-9]|3[01])\/(0[1-9]|1[0-2])\/\d{4}$/;

if (!regex.test(texto)) {
  return [{ json: { valido: false, motivo: 'Formato inválido (dd/MM/yyyy)' } }];
}

// 2. Validar que la fecha exista realmente
const [dia, mes, anio] = texto.split('/').map(Number);
const fecha = new Date(anio, mes - 1, dia);

const fechaValida =
  fecha.getFullYear() === anio &&
  fecha.getMonth() === mes - 1 &&
  fecha.getDate() === dia;

if (!fechaValida) {
  return [{ json: { valido: false, motivo: 'La fecha no existe' } }];
}

// 3. Fecha válida
return [{
  json: {
    valido: true,
    fecha_original: texto,
    fecha_date: fecha.toISOString()
  }
}];

const appointments = $('GetTurnos1').all().map(i => i.json);
const horarios = $('GetHorario').all().map(i => i.json);

const doctorNombre = $('GetDoctor').first().json.nombre;
const duracion_consulta = $('GetDoctor').first().json.duracion_consulta; // minutos
const fechaISO = $('Code in JavaScript1').first().json.fecha_date;

const fecha = new Date(fechaISO);
const diaSemana = fecha.getUTCDay(); // 0=domingo ... 6=sábado
let prefix;
const horariosDelDia = horarios.filter(h => h.dia_semana === diaSemana);
if(doctorNombre.startsWith("Dr.")){
  prefix = 'el';
} else {
  prefix = 'la';
}
const citasReservadas = appointments
  .filter(a => a.estado === 'reservado')
  .map(a => ({
    inicio: new Date(a.fecha_hora_inicio),
    fin: new Date(a.fecha_hora_fin),
  }));

const disponibles = [];

for (const h of horariosDelDia) {
  let hora = h.hora_inicio;

  while (hora < h.hora_fin) {
    const horas = Math.floor(hora / 100);
    const minutos = hora % 100;

    const inicioSlot = new Date(fecha);
    inicioSlot.setUTCHours(horas, minutos, 0, 0);

    const finSlot = new Date(inicioSlot);
    finSlot.setMinutes(finSlot.getMinutes() + duracion_consulta);

    const ocupado = citasReservadas.some(c =>
      inicioSlot < c.fin && finSlot > c.inicio
    );

    if (!ocupado && finSlot.getUTCHours() * 100 + finSlot.getUTCMinutes() <= h.hora_fin) {
      disponibles.push(inicioSlot.toISOString().substring(11, 16));
    }

    // ⏭ avanzar según duración real
    const totalMin = minutos + duracion_consulta;
    hora = horas * 100 + totalMin;

    // corregir overflow de minutos (> 60)
    if (hora % 100 >= 60) {
      hora += Math.floor((hora % 100) / 60) * 40;
    }
  }
}

const emojis = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];
const fechaTexto = fecha.toLocaleDateString('es-ES');
let mensaje;

if (disponibles.length === 0) {
  mensaje = `❌ No hay horarios disponibles para ${prefix} ${doctorNombre} el ${fechaTexto}.\n\n` +
            `Por favor, elegí otra fecha o contactá con recepción.`;
} else {
  const emojis = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];

  mensaje = `Estos son los horarios disponibles para ${prefix} ${doctorNombre} el ${fechaTexto}:\n\n`;

  disponibles.forEach((h, i) => {
    mensaje += `${emojis[i] || '⏱️'} ${h}\n`;
  });

  mensaje += `\nRespondé escribiendo el numero de la hora exacta que prefieras. \n(Ejemplo: 2)`;
}

return [
  {
    json: {
      mensaje,
      horariosDisponibles: disponibles,
      hayDisponibilidad: disponibles.length > 0,
      duracion_consulta
    }
  }
];
